### Basic Data Table Setup with Filtering in React

Source: https://github.com/calcom/cal.com/blob/main/packages/features/data-table/GUIDE.md

Demonstrates how to set up a basic data table using Cal.com's data table components. It includes defining data types, configuring columns with filtering options, and rendering the table with a provider and wrapper. This snippet assumes the availability of 'users' data and other necessary hooks like 'useReactTable' and 'usePathname'.

```tsx
import {
  DataTableProvider,
  DataTableWrapper,
  DataTableFilters,
  useDataTable,
  ColumnFilterType,
} from "@calcom/features/data-table";

// 1. Define your data type
type User = {
  id: number;
  name: string;
  email: string;
  role: string;
};

// 2. Create columns with filtering support
const columns = [
  {
    id: "name",
    header: "Name",
    accessorKey: "name",
    meta: {
      type: ColumnFilterType.TEXT,
    },
  },
  {
    id: "role",
    header: "Role",
    accessorKey: "role",
    meta: {
      type: ColumnFilterType.SINGLE_SELECT,
    },
  },
];

// 3. Setup the table
function UserTable() {
  const table = useReactTable({
    data: users, // Assuming 'users' is defined elsewhere
    columns,
    // ... other table options
  });

  const pathname = usePathname(); // Assuming 'usePathname' is imported
  const tableIdentifier = "hard-coded idenfidier"; // or pathname;

  return (
    <DataTableProvider tableIdentifier={tableIdentifier}>
      <DataTableWrapper
        table={table}
        paginationMode="standard"
        ToolbarLeft={
          <>
            <DataTableToolbar.SearchBar />
            <DataTableFilters.FilterBar table={table} />
          </>
        }
        ToolbarRight={
          <>
            <DataTableFilters.ClearFiltersButton />
            <DataTableSegment.SaveButton />
            <DataTableSegment.Select />
          </>
        }
      />
    </DataTableProvider>
  );
}

```

